module.render:
const color = args.color || 'var(--accent-color)';
const active = parseInt(args.active, 10) || 0;
const numbered = String(args.numbered) === 'true';
const compact = String(args.compact) === 'true';
const align = args.align === 'center' ? 'center' : 'left';
const lineColor = (args.linecolor || '').trim();
const phases = sections.map((s) => (s || '').trim()).filter(Boolean);
let styleVars = `--rm-color:${color};`;
if (lineColor) styleVars += `--rm-line:${lineColor};`;
if (align !== 'left') styleVars += `--rm-body-align:${align};`;
const cls = 'mdp-mod-roadmap' + (numbered ? ' is-numbered' : '') + (compact ? ' is-compact' : '');
let html = `\n\n<div class="${cls}" style="${styleVars}"><div class="mdp-rm-track">`;
phases.forEach((p, i) => {
  const lines = p.split('\n');
  const title = (lines.shift() || '').trim();
  const body = lines.join('\n').trim();
  const on = (i + 1) === active;
  const dotInner = numbered ? String(i + 1) : '';
  html += `<div class="mdp-rm-phase${on ? ' is-active' : ''}"><div class="mdp-rm-dot">${dotInner}</div><div class="mdp-rm-title">\n\n${title}\n\n</div><div class="mdp-rm-body">\n\n${body}\n\n</div></div>`;
});
html += `</div></div>\n\n`;
return html;
